package streambroker

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/streambroker"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type StreamBrokerProxy struct {
	streambroker.UnimplementedStreamBrokerServer
	client streambroker.StreamBrokerClient
}

func init() {
	proxyutil.Register(&streambroker.StreamBroker_ServiceDesc, NewStreamBrokerProxy)
}
func NewStreamBrokerProxy(cc grpc.ClientConnInterface) streambroker.StreamBrokerServer {
	return &StreamBrokerProxy{client: streambroker.NewStreamBrokerClient(cc)}
}
func (p *StreamBrokerProxy) Put(ctx context.Context, in *streambroker.Message) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[streambroker.Message, emptypb.Empty](p.client.Put)(ctx, in)
}
